mapper.select:
SELECT st.name AS studentName, l.title AS lessonName, ls.score AS score, ls.evaluation AS evaluation, sf.name AS evaluateTeacherName, ls.evaluate_time AS evaluateTime FROM lesson_student ls LEFT JOIN student st ON ls.student_id = st.id LEFT JOIN lesson l ON ls.lesson_id = l.id LEFT JOIN staff sf ON ls.evaluate_teacher = sf.id
AND ls.lesson_id = #{lessonId}
AND ls.evaluate_teacher = #{teacherId}
AND ls.student_id = #{studentId}
AND ls.evaluation LIKE CONCAT('%', #{evaluation}, '%')
AND DATE(ls.evaluate_time) >= #{startTime}
AND DATE(ls.evaluate_time) <= #{endTime}
ORDER BY ls.evaluate_time DESC
